            // Preserve old format for existing documents.
            entity.HasIdProperty(useOldFormat: true);

            // Breaking change #3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws at runtime in 9.0. Removed.
        });
    }
}
