using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // Breaking change #5: Sync I/O now throws by default.
        // Suppress until async migration is complete.
        optionsBuilder.ConfigureWarnings(w => w.Ignore(
            Microsoft.EntityFrameworkCore.Diagnostics.CosmosEventId.SyncNotSupported));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change #1: Discriminator property renamed from "Discriminator" to "$type".
            // Preserve old property name so existing documents are still queryable.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: id no longer includes the discriminator (was "Blog|8", now "8").
            // Preserve old id format for existing documents.
            entity.HasDiscriminatorInJsonId();

            // Breaking change #3: Key property is now mapped directly to JSON "id".
            // Preserve the old shadow-id behavior so the key is stored separately.
            entity.HasShadowId();

            // Breaking change #4: HasIndex() now throws instead of being silently ignored.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

